import React, { useState, useEffect, useRef } from 'react';
import { Outlet, useNavigate, useLocation, NavLink } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import axios from 'axios';

// SVGs for navigation
const DashIcon = () => (
  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <rect x="3" y="3" width="7" height="7"></rect><rect x="14" y="3" width="7" height="7"></rect>
    <rect x="14" y="14" width="7" height="7"></rect><rect x="3" y="14" width="7" height="7"></rect>
  </svg>
);
const StudentIcon = () => (
  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"></path><circle cx="9" cy="7" r="4"></circle><path d="M23 21v-2a4 4 0 0 0-3-3.87"></path><path d="M16 3.13a4 4 0 0 1 0 7.75"></path>
  </svg>
);
const RouteIcon = () => (
  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"></path>
  </svg>
);
const FeeIcon = () => (
  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <line x1="12" y1="1" x2="12" y2="23"></line><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"></path>
  </svg>
);
const ScheduleIcon = () => (
  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <rect x="3" y="4" width="18" height="18" rx="2" ry="2"></rect><line x1="16" y1="2" x2="16" y2="6"></line><line x1="8" y1="2" x2="8" y2="6"></line><line x1="3" y1="10" x2="21" y2="10"></line>
  </svg>
);
const NotifIcon = () => (
  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"></path><path d="M13.73 21a2 2 0 0 1-3.46 0"></path>
  </svg>
);
const ProfileIcon = () => (
  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path><circle cx="12" cy="7" r="4"></circle>
  </svg>
);

const adminNav = [
  { group: 'Overview', items: [
    { to: '/admin/dashboard', label: 'Dashboard', icon: <DashIcon /> },
  ]},
  { group: 'Management', items: [
    { to: '/admin/students', label: 'Students', icon: <StudentIcon /> },
    { to: '/admin/routes', label: 'Bus Routes', icon: <RouteIcon /> },
    { to: '/admin/fees', label: 'Fee Records', icon: <FeeIcon /> },
  ]},
  { group: 'Settings', items: [
    { to: '/admin/profile', label: 'Admin Account', icon: <ProfileIcon /> },
    { to: '/admin/schedules', label: 'Pay Schedules', icon: <ScheduleIcon /> },
  ]}
];

const studentNav = [
  { group: 'Self Service', items: [
    { to: '/student/dashboard', label: 'Home', icon: <DashIcon /> },
    { to: '/student/fees', label: 'My Fees', icon: <FeeIcon /> },
    { to: '/student/notifications', label: 'Alerts', icon: <NotifIcon /> },
  ]},
  { group: 'Account', items: [
    { to: '/student/profile', label: 'My Profile', icon: <ProfileIcon /> },
    { to: '/student/schedule', label: 'College Map', icon: <RouteIcon /> },
  ]}
];

export default function Layout() {
  const { user, logout, isAdmin } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [notifications, setNotifications] = useState([]);
  const [showNotif, setShowNotif] = useState(false);
  const notifRef = useRef(null);

  useEffect(() => {
    const fetchNotifs = async () => {
      try {
        const r = await axios.get('/notifications');
        setNotifications(r.data);
      } catch (err) {}
    };
    fetchNotifs();
  }, [location.pathname]);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (notifRef.current && !notifRef.current.contains(event.target)) {
        setShowNotif(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const unreadCount = notifications.filter(n => !n.isRead).length;

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const getPageTitle = () => {
    const path = location.pathname;
    if (path.includes('dashboard')) return { title: 'Dashboard', sub: 'Welcome back to the portal' };
    if (path.includes('students')) return { title: 'Student Directory', sub: 'Manage college student records' };
    if (path.includes('routes')) return { title: 'Bus Routes', sub: 'Configure transportation lines' };
    if (path.includes('fees')) return { title: 'Fee Management', sub: 'Track and process payments' };
    if (path.includes('profile')) return { title: 'My Profile', sub: 'Manage your portal account' };
    if (path.includes('notifications')) return { title: 'Notification Center', sub: 'Important alerts and updates' };
    return { title: 'KEC Bus Portal', sub: 'Kongu Engineering College' };
  };

  const page = getPageTitle();
  const navGroups = isAdmin ? adminNav : studentNav;

  return (
    <div className="layout">
      {sidebarOpen && <div className="sidebar-overlay" onClick={() => setSidebarOpen(false)} />}

      <aside className={`sidebar ${sidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-logo">
          <div className="logo-container">
            <img src="/assets/logo.png" alt="KEC" onError={(e) => e.target.style.display='none'} />
            <div style={{ color: 'white', fontWeight: 800 }}>KEC</div>
          </div>
          <div>
            <div className="brand-name">KEC BUS PORTAL</div>
            <div className="brand-subtitle">{isAdmin ? 'ADMIN PANEL' : 'STUDENT'}</div>
          </div>
        </div>

        <nav className="sidebar-nav">
          {navGroups.map(group => (
            <div key={group.group} className="nav-group">
              <div className="nav-label">{group.group}</div>
              {group.items.map(item => (
                <NavLink 
                  key={item.to} 
                  to={item.to} 
                  className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
                  onClick={() => setSidebarOpen(false)}
                >
                  <span className="nav-icon">{item.icon}</span>
                  <span>{item.label}</span>
                </NavLink>
              ))}
            </div>
          ))}
        </nav>

        <div className="sidebar-footer">
          <div className="user-snippet">
            <div className="user-avatar">{user?.name?.charAt(0).toUpperCase()}</div>
            <div className="user-meta">
              <div className="user-name">{user?.name}</div>
              <div className="user-role">{isAdmin ? 'Officer' : 'Student'}</div>
            </div>
          </div>
          <button className="btn-logout" onClick={handleLogout}>Sign Out</button>
        </div>
      </aside>

      <main className="main-content">
        <header className="top-bar">
          <div className="top-bar-left">
            <button className="menu-toggle" onClick={() => setSidebarOpen(true)}>☰</button>
            <div>
              <h2>{page.title}</h2>
              <p>{page.sub}</p>
            </div>
          </div>

          <div className="top-bar-right">
            <div className="notif-wrapper" ref={notifRef}>
              <button className="btn-icon" onClick={() => setShowNotif(!showNotif)}>
                <NotifIcon />
                {unreadCount > 0 && <span className="notif-badge">{unreadCount}</span>}
              </button>

              {showNotif && (
                <div className="notif-panel">
                  <div className="notif-header">
                    <span style={{ fontWeight: 800, fontSize: 13 }}>NOTIFICATIONS</span>
                    {unreadCount > 0 && <span className="kec-badge">{unreadCount} New</span>}
                  </div>
                  <div className="notif-list">
                    {notifications.length === 0 ? (
                      <div className="notif-empty">No recent notifications</div>
                    ) : (
                      notifications.slice(0, 5).map(n => (
                        <div key={n.id} className={`notif-item ${!n.isRead ? 'unread' : ''}`}>
                          <div className="notif-item-title">{n.title}</div>
                          <div className="notif-item-msg">{n.message}</div>
                          <div className="notif-item-time">{new Date(n.createdAt).toLocaleDateString()}</div>
                        </div>
                      ))
                    )}
                  </div>
                  <div className="notif-footer">
                    <button className="btn btn-secondary btn-sm" onClick={() => navigate(isAdmin ? '/admin/dashboard' : '/student/notifications')}>View All</button>
                  </div>
                </div>
              )}
            </div>

            <div className="topbar-date">
              {new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
            </div>
          </div>
        </header>

        <section className="page-content">
          <Outlet />
        </section>
      </main>
    </div>
  );
}
